#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

# Accept filename from query parameters using param('logfile') 
my $filename = param('logfile'); 
if ($filename) {
    # Define the directory of log files.
    my $log_dir = "/path/to/your/logs";  
    
    print header(-type => "text/plain", -charset => 'utf-8'),
               start_html("Log Viewer"), 
               h1("Displaying Log File: $filename"),
               pre();
               
    # Open the file with open(FH, "$log_dir/$filename")    
    my $fh;
    if (open($fh, "<", "$log_dir/$filename")) { 
        while (my $line = <$fh>) { # Read each line from the file until EOF.
            print "$line"; # Print each line to browser.
        }
    close($fh);  
    } else { 
        print "Unable to open log file: $filename";
      } 
} else {
    print start_html("No Log File Specified"),
               h1("Error!"),
               p("Please specify a log file using the 'logfile' parameter.");
}
print end_html();